#include<bits/stdc++.h>
using namespace std;
long long cnt1[11],cnt2[11],dp[21][2][11];
long long a[21],base[21],f[21];
void solve(long long x,long long *cnt)
{
    long long tot=0;
    while(x)
    {
        a[++tot]=x%10;
        x/=10;
    }
    for(long long i=tot;i>=1;i--)
    {
        for(long long j=0;j<=9;j++)
        {
            cnt[j]+=f[i-1]*a[i];
        }
        for(long long j=0;j<a[i];j++)
        {
            cnt[j]+=base[i-1];
        }
        long long s=0;
        for(long long j=i-1;j>=1;j--)
        {
            s=s*10+a[j];
        }
        cnt[a[i]]+=s+1;
        cnt[0]-=base[i-1];
    }
}
int main()
{
    long long l,r;
    scanf("%lld%lld",&l,&r);
    base[0]=1;
    for(long long i=1;i<=15;i++)
    {
        f[i]=f[i-1]*10+base[i-1];
        base[i]=base[i-1]*10;
    }
    solve(l-1,cnt2);
    solve(r,cnt1);
    for(long long j=0;j<=9;j++)
    {
        printf("%lld ",cnt1[j]-cnt2[j]);
    }
    return 0;
}
